          isOpen={false}
          task={mockTask}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
      );
      expect(container.firstChild).toBeNull();
    });

    it("returns null when no task", () => {
      const { container } = render(
        <TaskEditModal
          isOpen={true}
          task={null}
          onClose={mockOnClose}
          onSave={mockOnSave}
          setTaskToEdit={mockSetTaskToEdit}
        />,
