      await user.click(screen.getByRole("button", { name: "Salvesta" }));

      await waitFor(() => {
        expect(screen.getByText("Failed")).toBeInTheDocument();
      });
      expect(mockOnClose).not.toHaveBeenCalled();
    });
  });
});

