  it("tag menu items invoke correct callbacks", () => {
    const onOpenVariantsFromMenu = vi.fn();
    const onEditTag = vi.fn();
    const onDeleteTag = vi.fn();
    render(
      <SynthesisView
        {...baseProps}
        onOpenVariantsFromMenu={onOpenVariantsFromMenu}
        onEditTag={onEditTag}
        onDeleteTag={onDeleteTag}
      />,
